@app.route('/order/<int:order_id>')
def order_details(order_id):
    orders = read_orders()
    order = next((o for o in orders if o['order_id'] == order_id), None)
    if not order:
        return redirect(url_for('order_history'))

    order_items_all = read_order_items()
